}

void quicksort(std::vector<int>& arr, int low, int high) {
    while (low < high) {
        if (high - low < 32) {
            for (int i = low + 1; i <= high; ++i) {
                int v = arr[i];
                if (v < arr[i - 1]) {
                    int j = i - 1;
                    while (j >= low && arr[j] > v) { arr[j + 1] = arr[j]; j--; }
                    arr[j + 1] = v;
                }
            }
            return;
        }
        int mid = low + (high - low) / 2;
        if (arr[mid] < arr[low]) std::swap(arr[mid], arr[low]);
        if (arr[high] < arr[low]) std::swap(arr[high], arr[low]);
        if (arr[high] < arr[mid]) std::swap(arr[high], arr[mid]);
        int p = arr[mid], i = low - 1, j = high + 1;
        while (true) {
            while (arr[++i] < p);
            while (arr[--j] > p);
            if (i >= j) break;
            std::swap(arr[i], arr[j]);
        }
        if (j - low < high - j) { quicksort(arr, low, j); low = j + 1; }
        else { quicksort(arr, j + 1, high); high = j; }
    }
}

